import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.CTpQozEL.js";const d=JSON.parse('{"title":"Hostinger","description":"Hostinger 1-Click 또는 VPS로 영속 OpenClaw Gateway 배포하기","frontmatter":{"title":"Hostinger","description":"Hostinger 1-Click 또는 VPS로 영속 OpenClaw Gateway 배포하기"},"headers":[],"relativePath":"install/hostinger.md","filePath":"install/hostinger.md","lastUpdated":null}'),n={name:"install/hostinger.md"};function l(s,e,i,p,c,g){return t(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="hostinger" tabindex="-1">Hostinger <a class="header-anchor" href="#hostinger" aria-label="Permalink to &quot;Hostinger&quot;">​</a></h1><p><a href="https://www.hostinger.com/openclaw" target="_blank" rel="noreferrer">Hostinger</a>에서 <strong>1-Click</strong> 관리형 배포 또는 <strong>VPS</strong> 설치로 영속 OpenClaw Gateway를 실행할 수 있습니다.</p><h2 id="사전-준비" tabindex="-1">사전 준비 <a class="header-anchor" href="#사전-준비" aria-label="Permalink to &quot;사전 준비&quot;">​</a></h2><ul><li>Hostinger 계정 (<a href="https://www.hostinger.com/openclaw" target="_blank" rel="noreferrer">가입</a>)</li><li>약 5~10분의 시간</li></ul><h2 id="옵션-a-1-click-openclaw" tabindex="-1">옵션 A: 1-Click OpenClaw <a class="header-anchor" href="#옵션-a-1-click-openclaw" aria-label="Permalink to &quot;옵션 A: 1-Click OpenClaw&quot;">​</a></h2><p>시작하는 가장 빠른 방법입니다. Hostinger가 인프라, Docker, 자동 업데이트를 처리합니다.</p><ol><li><p><strong>구매 및 실행</strong></p><ol><li><p><a href="https://www.hostinger.com/openclaw" target="_blank" rel="noreferrer">Hostinger OpenClaw 페이지</a>에서 Managed OpenClaw 플랜을 선택하고 결제를 완료합니다.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p></div></li></ol><p>결제 중에 <strong>Ready-to-Use AI</strong> 크레딧을 선택할 수 있습니다. 사전 구매되어 OpenClaw 내부에 즉시 통합되므로 다른 제공업체의 외부 계정이나 API 키가 필요하지 않습니다. 바로 대화를 시작할 수 있습니다. 또는 설정 중에 Anthropic, OpenAI, Google Gemini, xAI의 자체 키를 제공할 수도 있습니다. :::</p></li><li><p><strong>메시지 채널 선택</strong></p></li></ol><p>연결할 채널을 하나 이상 선택합니다:</p><pre><code>   - **WhatsApp** — 설정 마법사에 표시된 QR 코드를 스캔합니다.
   - **Telegram** — [BotFather](https://t.me/BotFather)에서 봇 토큰을 붙여넣습니다.
</code></pre><ol start="3"><li><strong>설치 완료</strong></li></ol><p><strong>Finish</strong>를 클릭하여 인스턴스를 배포합니다. 준비가 끝나면 hPanel의 <strong>OpenClaw Overview</strong>에서 OpenClaw 대시보드에 접근합니다.</p><h2 id="옵션-b-vps에서-openclaw-실행" tabindex="-1">옵션 B: VPS에서 OpenClaw 실행 <a class="header-anchor" href="#옵션-b-vps에서-openclaw-실행" aria-label="Permalink to &quot;옵션 B: VPS에서 OpenClaw 실행&quot;">​</a></h2><p>서버에 대한 통제권이 더 큽니다. Hostinger가 VPS에 Docker로 OpenClaw를 배포하고, hPanel의 <strong>Docker Manager</strong>를 통해 관리합니다.</p><ol><li><p><strong>VPS 구매</strong></p><ol><li><p><a href="https://www.hostinger.com/openclaw" target="_blank" rel="noreferrer">Hostinger OpenClaw 페이지</a>에서 OpenClaw on VPS 플랜을 선택하고 결제를 완료합니다.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p></div></li></ol><p>결제 중에 <strong>Ready-to-Use AI</strong> 크레딧을 선택할 수 있습니다. 사전 구매되어 OpenClaw 내부에 즉시 통합되므로 외부 계정이나 다른 제공업체의 API 키 없이도 바로 대화를 시작할 수 있습니다. :::</p></li><li><p><strong>OpenClaw 설정</strong></p></li></ol><p>VPS가 프로비저닝되면 설정 필드를 채웁니다:</p><pre><code>   - **Gateway 토큰** — 자동 생성됩니다. 나중에 사용할 수 있도록 저장해 두세요.
   - **WhatsApp 번호** — 국가 코드를 포함한 번호 (선택 사항).
   - **Telegram 봇 토큰** — [BotFather](https://t.me/BotFather)에서 발급 (선택 사항).
   - **API 키** — 결제 중 Ready-to-Use AI 크레딧을 선택하지 않은 경우에만 필요합니다.
</code></pre><ol start="3"><li><strong>OpenClaw 시작</strong></li></ol><p><strong>Deploy</strong>를 클릭합니다. 실행되면 hPanel에서 <strong>Open</strong>을 클릭해 OpenClaw 대시보드를 엽니다.</p><p>로그, 재시작, 업데이트는 hPanel의 Docker Manager 인터페이스에서 직접 관리됩니다. 업데이트하려면 Docker Manager에서 <strong>Update</strong>를 누르세요. 최신 이미지를 가져옵니다.</p><h2 id="설정-확인" tabindex="-1">설정 확인 <a class="header-anchor" href="#설정-확인" aria-label="Permalink to &quot;설정 확인&quot;">​</a></h2><p>연결한 채널에서 어시스턴트에게 &quot;Hi&quot;를 보내보세요. OpenClaw가 응답하며 초기 선호도 설정을 안내합니다.</p><h2 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h2><p><strong>대시보드가 로드되지 않음</strong> — 컨테이너 프로비저닝이 완료될 때까지 몇 분 기다리세요. hPanel의 Docker Manager 로그를 확인하세요.</p><p><strong>Docker 컨테이너가 계속 재시작됨</strong> — Docker Manager 로그를 열고 설정 오류를 찾으세요 (누락된 토큰, 잘못된 API 키).</p><p><strong>Telegram 봇이 응답하지 않음</strong> — 페어링 코드 메시지를 Telegram에서 OpenClaw 채팅 내부에 직접 메시지로 보내 연결을 완료하세요.</p><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/channels/">채널</a> — Telegram, WhatsApp, Discord 등 연결</li><li><a href="/openclaw-docs-ko/gateway/configuration">Gateway 설정</a> — 모든 설정 옵션</li></ul>`,27)])])}const w=a(n,[["render",l]]);export{d as __pageData,w as default};
